import java.io.FileWriter;
import java.io.IOException;
import java.io.PrintWriter;

public class XSSSecureCode {

    public static void main(String[] args) throws IOException {
        // Simulated user input containing malicious script
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Sanitize user input to prevent XSS
        userInput = sanitizeUserInput(userInput);

        // Writing sanitized output to a file
        try (PrintWriter out = new PrintWriter(new FileWriter("index.html"))) {
            out.println("<html>");
            out.println("<body>");
            out.println("<h1>Welcome, " + userInput + "</h1>");
            out.println("</body>");
            out.println("</html>");
        }
    }

    private static String sanitizeUserInput(String input) {
        // Replace special characters that can be used for XSS attacks
        return input.replaceAll("<", "&lt;")
                    .replaceAll(">", "&gt;")
                    .replaceAll("\"", "&quot;")
                    .replaceAll("'", "&#39;");
    }
}

### Explanation:
